12	export function processScenario(scenario: any): any {
13	  const step = scenario.steps[0];
14	  if (step.items.length === 0) {
15	    return { results: [{ premium: PROCESSING_FEE }] };
16	  }
17	  let basePremium = 0;
18	  for (const item of step.items) {
19	    basePremium += BASE_PREMIUM[item.type];
20	  }
21	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_RATE;
22	  const premium = basePremium + firstInsuranceSurcharge + PROCESSING_FEE;
23	  return { results: [{ premium }] };
24	}
